/**
 * DNN forward pass.
 * obs:    input array  [6] — [pitch, pitch_rate, wheel_vel_left, wheel_vel_right]
 * output: output array [2] — [left_motor, right_motor], range approx [-1, 1]
 *
 * Note: clamp output to [-1, 1] before sending to motor driver.
 */
static inline void actor_forward(const float* obs, float* output) {
    float buf0[32];
    float buf1[32];
    const float* in  = obs;
    float*       out = buf0;

    // Layer 0: 6 -> 32, activation=tanh
    for (int o = 0; o < 32; o++) {
        float acc = layer0_bias[o];
        for (int j = 0; j < 6; j++)
            acc += layer0_weight[o * 6 + j] * in[j];
        out[o] = tanhf(acc);
    }
    in  = out;
    out = (out == buf0) ? buf1 : buf0;

    // Layer 1: 32 -> 32, activation=tanh
    for (int o = 0; o < 32; o++) {
        float acc = layer1_bias[o];
        for (int j = 0; j < 32; j++)
            acc += layer1_weight[o * 32 + j] * in[j];
        out[o] = tanhf(acc);
    }
    in  = out;
    out = (out == buf0) ? buf1 : buf0;

    // Layer 2: 32 -> 2, activation=none (output layer)
    for (int o = 0; o < 2; o++) {
        float acc = layer2_bias[o];
        for (int j = 0; j < 32; j++)
            acc += layer2_weight[o * 32 + j] * in[j];
        out[o] = acc;
    }
    for (int o = 0; o < 2; o++)
        output[o] = out[o];

}